+    asx_process_spawn_options opts;
+    uint32_t i;
+    asx_process_reset();
+    opts.program = "cap";
+    opts.polls_until_exit = 0u;
+    opts.exit_code = 0;
+    opts.auto_exit = 0;
+    for (i = 0; i < ASX_MAX_PROCESSES; i++) {
